metadata.initialCode:
import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  // Directly fetch the venue-specific funding snapshot for ETH.
  // This is a single endpoint call, so no same-endpoint batching is used.
  const result = await callMcpSkill({
    toolId: "b940bedc-3d67-45b0-8709-b3d070e5e454",
    toolName: "get_funding_analysis",
    args: { coin: "ETH" }
  });

  const hyperliquid = result?.venueFundingSnapshot?.Hyperliquid || null;
  const binance = result?.venueFundingSnapshot?.Binance || null;

  const hyperliquidRate = typeof hyperliquid?.rate === "number" ? hyperliquid.rate : null;
  const binanceRate = typeof binance?.rate === "number" ? binance.rate : null;

  const fundingSpread =
    hyperliquidRate !== null && binanceRate !== null
      ? hyperliquidRate - binanceRate
      : null;

  const hasArbitrageSpread =
    result?.fundingArbitrage !== null &&
    result?.fundingArbitrage !== undefined &&
    fundingSpread !== null;

  return {
    coin: result?.coin,
    comparison: {
      Hyperliquid: hyperliquid,
      Binance: binance
    },
    fundingSpread: {
      hyperliquidMinusBinance: fundingSpread,
      hasFundingArbitrageSpread: hasArbitrageSpread,
      fundingArbitrage: result?.fundingArbitrage || null
    },
    confidence: result?.confidence,
    dataFreshness: result?.dataFreshness,
    fetchedAt: result?.fetchedAt
  };
}

